import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { Project } from '../../shared/models';
import { PortfolioService } from '../../core/services/portfolio.service';

@Component({
  selector: 'app-project-detail',
  templateUrl: './project-detail.component.html',
  styleUrls: ['./project-detail.component.scss']
})
export class ProjectDetailComponent implements OnInit {
  project?: Project;

  constructor(private route: ActivatedRoute, private portfolioService: PortfolioService) {}

  ngOnInit(): void {
    const slug = this.route.snapshot.paramMap.get('slug');
    if (slug) {
      this.portfolioService.getProjectBySlug(slug).subscribe(project => this.project = project);
    }
  }

  techList(technologies: string): string[] {
    return technologies.split(',').map(t => t.trim()).filter(Boolean);
  }
}
<section class="section" *ngIf="project">
  <div class="container project-detail">
    <span class="term-label">cat projects/{{ project.slug }}.md</span>
    <h1>{{ project.title }}</h1>
    <p class="project-detail__subtitle">{{ project.subtitle }}</p>

    <div class="project-detail__tags">
      <span class="tag" *ngFor="let tech of techList(project.technologies)">{{ tech }}</span>
    </div>

    <div class="project-detail__links" *ngIf="project.gitHubUrl || project.demoUrl">
      <a *ngIf="project.gitHubUrl" [href]="project.gitHubUrl" target="_blank" rel="noopener" class="btn">GitHub</a>
      <a *ngIf="project.demoUrl" [href]="project.demoUrl" target="_blank" rel="noopener" class="btn btn--solid">Live Demo</a>
    </div>

    <h2>Problem</h2>
    <p>{{ project.problem }}</p>

    <h2>Solution</h2>
    <p>{{ project.solution }}</p>

    <h2>Architecture</h2>
    <p>{{ project.architecture }}</p>

    <h2>My Role</h2>
    <p>{{ project.myRole }}</p>

    <h2>Outcome</h2>
    <p>{{ project.outcome }}</p>

    <h2>Lessons Learned</h2>
    <p>{{ project.lessonsLearned }}</p>

    <a routerLink="/projects" class="btn">&larr; Back to all projects</a>
  </div>
</section>

<section class="section" *ngIf="!project">
  <div class="container">
    <p>Project not found.</p>
    <a routerLink="/projects" class="btn">&larr; Back to all projects</a>
  </div>
</section>
